<?php require_once __DIR__.'/../inc/bootstrap.php'; $d=db_try(); if(!$d['ok']){ echo jarvis_render_notice('<pre>'.h($d['message']).'</pre>','error'); exit; } $pdo=$d['pdo']; $action=$_GET['action']??''; $file=basename((string)($_GET['file']??'')); $root=jarvis_data_path('sql/postgres'); if($action==='preview'){ $abs=sql_abs($file); if(!is_file($abs)){ echo jarvis_render_notice('Fichier SQL introuvable.','warning'); exit; } echo '<pre>'.h((string)file_get_contents($abs)).'</pre>'; exit; } if($action==='manual'){ $sql=trim((string)($_POST['sql']??'')); if($sql===''){ echo jarvis_render_notice('Requête vide.','warning'); exit; } try{ if(preg_match('/^\s*select\b/i',$sql)){ $stmt=$pdo->query($sql); $rows=$stmt->fetchAll(); if(!$rows){ echo jarvis_render_notice('SELECT exécuté, aucune ligne.','info'); exit; } $cols=array_keys($rows[0]); echo '<table><thead><tr>'; foreach($cols as $c) echo '<th>'.h($c).'</th>'; echo '</tr></thead><tbody>'; foreach($rows as $row){ echo '<tr>'; foreach($cols as $c) echo '<td><pre>'.h((string)$row[$c]).'</pre></td>'; echo '</tr>'; } echo '</tbody></table>'; } else { $count=$pdo->exec($sql); echo jarvis_render_notice('Requête exécutée. Lignes affectées : '.h((string)$count),'success'); } }catch(Throwable $e){ echo jarvis_render_notice('<pre>'.h($e->getMessage()).'</pre>','error'); } exit; } $files=array_values(array_filter(is_dir($root)?scandir($root):[], fn($f)=>str_ends_with($f,'.sql'))); ?>
<div class="stack"><div class="notice">Le SQL runner reste disponible. Ce n’était pas négociable.</div><div class="two"><div class="card"><h3>Fichiers SQL</h3><select id="sql-file-select"><option value="">-- Choisir un fichier --</option><?php foreach($files as $f): ?><option value="<?= h($f) ?>"><?= h($f) ?></option><?php endforeach; ?></select><div id="sql-preview" class="card" style="margin-top:12px"><p class="small">Choisis un fichier.</p></div></div><div class="card"><h3>Requête SQL manuelle</h3><form id="sql-manual-form"><textarea id="sql-manual-text" name="sql">SELECT current_database(), current_user;</textarea><div class="actions" style="margin-top:12px"><button class="primary-btn" type="submit">Exécuter la requête</button></div></form><div id="sql-manual-result" class="card" style="margin-top:12px"><p class="small">Le résultat apparaîtra ici.</p></div></div></div></div>
